#!/usr/bin/env python
"""
Bootstrap: Modular Design Stack
  - core/property_predictor.py: logP, TPSA, ESOL solubility, pKa, Lipinski, SA, stability
  - core/multisite_assembler.py: 20 multi-site scaffolds (tripodal, macrocyclic, cage, tetradentate)
  - core/reaction_assembler.py: 14 reaction SMARTS, synthesis route validation
  - core/construct_assembler.py: modular recognition+linker+click+support assembly
  - 37 tests, zero regression (443 total)

Requires: previous bootstraps + RDKit
Usage: python bootstrap_modular_stack.py
"""
import base64, os, sys

if os.path.isfile("core/universal_schema.py"): root="."
elif os.path.isfile(os.path.join("..","core","universal_schema.py")): root=".."; os.chdir(root)
else: print("ERROR: Run from MABE root"); sys.exit(1)

FILES = {
    'core/property_predictor.py': '',
    'core/multisite_assembler.py': '',
    'core/reaction_assembler.py': '',
    'core/construct_assembler.py': '',
    'tests/test_modular_stack.py': '',
}

for path, b64 in FILES.items():
    os.makedirs(os.path.dirname(path), exist_ok=True)
    content = base64.b64decode(b64).decode("utf-8")
    with open(path, "w", encoding="utf-8") as f:
        f.write(content)
    print(f"  Wrote {path} ({len(content)} bytes)")

print()
print("Done. Run:")
print("  python -m pytest tests/test_modular_stack.py -v")